mapper.select:
SELECT ID,JOB_NAME,JOB_GROUP,REQUEST_TYPE,HTTP_URL,HTTP_PARAMS,FIRE_TIME,RESULT FROM HTTPJOB_LOGS t WHERE 1=1
AND t.JOB_NAME = #{jobName}
AND t.JOB_GROUP = #{jobGroup}
AND ( t.JOB_NAME LIKE concat('%',#{searchParam},'%') OR t.JOB_GROUP LIKE concat('%',#{searchParam},'%') )
ORDER BY t.ID DESC
